import React from 'react';
import { useVideoConfig } from 'remotion';
import { PlacementBox, resolveSize } from '../../../lib/canvas';
import { Surface } from '../../../lib/primitives';
import { useStaggeredEntrance } from '../../../lib/hooks';
import { kanbanBoardSchema, type KanbanBoardProps } from './schema';

export { kanbanBoardSchema, type KanbanBoardProps };

/**
 * A data-driven Kanban board — glass `Surface` columns, each with a header,
 * a status dot, a ticket count, and a stack of small glass ticket cards. Every
 * card rises + fades in on the house spring, staggered across the whole board
 * (left-to-right, top-to-bottom) so it assembles as one calm cascade rather
 * than popping all at once. The board is static after the entrance — any
 * "flying ticket" between columns is the consumer's job, not this component's.
 * Self-contained except the shared `Surface` primitive and the
 * `useStaggeredEntrance` hook.
 *
 * @example
 * <KanbanBoard placement="center" />
 */
export const KanbanBoard: React.FC<KanbanBoardProps> = ({
  columns,
  width,
  gap,
  delay,
  stagger,
  fontSize,
  size,
  fontFamily,
  placement,
}) => {
  const { width: canvasW, height: canvasH } = useVideoConfig();
  const headerSize = size ? resolveSize(size, { width: canvasW, height: canvasH }) : fontSize;
  const cardSize = Math.round(headerSize * 0.82);
  const dim = 'var(--onda-dim, #8E8E98)';
  const faint = 'var(--onda-faint, #56565F)';
  // One hook call, then a per-index entrance — never a hook in a loop. A flat
  // running index across all cards keeps the cascade reading left-to-right,
  // top-to-bottom across the whole board.
  const at = useStaggeredEntrance({ type: 'rise', delay, increment: stagger });

  let cardIndex = 0;

  return (
    <PlacementBox placement={placement}>
      <div style={{ display: 'flex', gap, width, alignItems: 'stretch' }}>
        {columns.map((column, ci) => {
          const accent = column.accent ?? faint;
          return (
            <div key={ci} style={{ flex: 1, minWidth: 0 }}>
              <Surface variant="glass" padding={Math.round(gap * 0.9)} height="100%">
                <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
                  {/* Column header — status dot, title, ticket count */}
                  <div
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 10,
                      marginBottom: gap,
                    }}
                  >
                    <div
                      aria-hidden
                      style={{
                        width: Math.round(cardSize * 0.42),
                        height: Math.round(cardSize * 0.42),
                        borderRadius: '50%',
                        background: accent,
                        flexShrink: 0,
                      }}
                    />
                    <div
                      style={{
                        color: 'var(--onda-text, #F2F2F4)',
                        fontFamily,
                        fontSize: headerSize,
                        fontWeight: 600,
                        letterSpacing: '-0.02em',
                        lineHeight: 1,
                        flex: 1,
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                      }}
                    >
                      {column.title}
                    </div>
                    <div
                      style={{
                        color: column.accent ? accent : faint,
                        fontFamily: 'var(--onda-font-body, "Space Grotesk", sans-serif)',
                        fontSize: Math.round(cardSize * 0.78),
                        fontWeight: 500,
                        letterSpacing: '0.04em',
                        lineHeight: 1,
                      }}
                    >
                      {column.cards.length}
                    </div>
                  </div>

                  {/* Ticket cards */}
                  <div style={{ display: 'flex', flexDirection: 'column', gap: Math.round(gap * 0.6) }}>
                    {column.cards.map((label, ti) => {
                      const entrance = at(cardIndex);
                      cardIndex += 1;
                      return (
                        <div
                          key={ti}
                          style={{ opacity: entrance.opacity, transform: entrance.transform }}
                        >
                          <Surface variant="card" padding={Math.round(gap * 0.7)} shadow="none">
                            <div
                              style={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: 8,
                              }}
                            >
                              <div
                                aria-hidden
                                style={{
                                  width: 3,
                                  alignSelf: 'stretch',
                                  minHeight: cardSize,
                                  borderRadius: 2,
                                  background: accent,
                                  opacity: column.accent ? 0.9 : 0.4,
                                  flexShrink: 0,
                                }}
                              />
                              <div
                                style={{
                                  color: dim,
                                  fontFamily: 'var(--onda-font-body, "Space Grotesk", sans-serif)',
                                  fontSize: cardSize,
                                  fontWeight: 400,
                                  lineHeight: 1.35,
                                }}
                              >
                                {label}
                              </div>
                            </div>
                          </Surface>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </Surface>
            </div>
          );
        })}
      </div>
    </PlacementBox>
  );
};

export default KanbanBoard;

import { z } from 'zod';
import { placementSchema, sizeRoleSchema } from '../../../lib/canvas-schemas';

/** A single Kanban column: a header, an optional accent, and its ticket cards. */
export const kanbanColumnSchema = z.object({
  /** Column header (display font), e.g. `'In Progress'`. */
  title: z.string(),
  /** Status-dot + count color for this column. Defaults to a neutral dim token; one column should earn the rose. */
  accent: z.string().optional(),
  /** Ticket labels — one small glass card per entry, top-to-bottom. */
  cards: z.array(z.string()).default([]),
});

/** Inferred type for a single {@link KanbanBoard} column. */
export type KanbanColumn = z.infer<typeof kanbanColumnSchema>;

/** Zod schema for {@link KanbanBoard} props. */
export const kanbanBoardSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('kanban-board').default('kanban-board'),
  /** The columns, laid out left-to-right. Each holds its own ticket cards. */
  columns: z
    .array(kanbanColumnSchema)
    .default([
      {
        title: 'Todo',
        cards: ['Storyboard the intro', 'Source b-roll', 'Write VO script'],
      },
      {
        title: 'In Progress',
        accent: 'var(--onda-accent, #D96B82)',
        cards: ['Animate the title card', 'Color-grade scene 2'],
      },
      {
        title: 'Done',
        cards: ['Lock the edit', 'Render preview', 'Sound pass', 'Export master'],
      },
    ]),
  /** Overall board width in px. Split evenly across the columns. */
  width: z.number().default(1040),
  /** Gap between columns (and between cards within a column) in px. */
  gap: z.number().default(20),
  /** Frames before the first card enters. */
  delay: z.number().int().min(0).default(0),
  /** Frames between successive cards rising in. House stagger is 4. */
  stagger: z.number().int().min(0).default(4),
  /** Base column-header font size in px. Wins over `size` if both are passed. */
  fontSize: z.number().default(22),
  /** Semantic typography role for the column header — resolves to canvas-aware pixels via the smaller canvas dimension. `fontSize` wins when both are passed. */
  size: sizeRoleSchema.optional(),
  /** Onda display font for headers and ticket labels. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
  /** Where on the canvas this sits. Region (`'center'`, `'upper-third'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link KanbanBoard}. */
export type KanbanBoardProps = z.infer<typeof kanbanBoardSchema>;
